function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array(c + 1).fill(0).map(() => Array<number>());
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    class DSU {
        parent: number[];
        rank: number[];
        constructor(size: number) {
            this.parent = Array(size).fill(0).map((_, i) => i);
            this.rank = Array(size).fill(0);
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return false;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize DSU
    const dsu = new DSU(c + 1);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    // Track which nodes are online
    const online: boolean[] = Array(c + 1).fill(true);

    // For each DSU root, track the minimum node in its set
    const minInSet: number[] = Array(c + 1).fill(0);
    for (let i = 1; i <= c; i++) {
        minInSet[dsu.find(i)] = i;
    }

    // Process queries
    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                // Find the minimum online node in the same set
                let minOnline = -1;
                for (let i = 1; i <= c; i++) {
                    if (online[i] && dsu.find(i) === root) {
                        if (minOnline === -1 || i < minOnline) {
                            minOnline = i;
                        }
                    }
                }
                result.push(minOnline);
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

